#define ELEMENTS_PER_THREAD (8)
#define FUSION_DEGREE (4)

template<class T>
inline T conv_int(const int i){ return static_cast<T>(i); }

template<class T>
inline T mad(const T a, const T b, const T c){ return a*b+c; }

template<class T>
inline bool equal(const T a, const T b){ return a==b; }

template <class T, int blockdim, unsigned int granularity, unsigned int fusion_degree, unsigned int compute_iterations, bool TemperateUnroll>
void benchmark_func(T seed, T *g_data, size_t size){
    const unsigned int blockSize = blockdim;
    const int stride = blockSize;
    const size_t total_elements = size / sizeof(T);
    const size big_stride = total_elements / (fusion_degree * granularity);

    #pragma omp parallel for
    for(size_t blockIdx = 0; blockIdx < big_stride / blockSize; blockIdx++){
        size_t idx = blockIdx * blockSize * granularity;

        T tmps[granularity];

        for(unsigned int k=0; k<fusion_degree; k++){
            for(unsigned int j=0; j<granularity; j++){
                tmps[j] = g_data[idx + j*stride + k*big_stride];

                for(unsigned int i=0; i<compute_iterations; i++){
                    tmps[j] = mad(tmps[j], tmps[j], seed);
                }
            }

            T sum = conv_int<T>(0);
            for(unsigned int j=0; j<granularity; j+=2)
                sum = mad(tmps[j], tmps[j+1], sum);

            if(equal(sum, conv_int<T>(-1)))
                g_data[idx + k*big_stride] = sum;
        }
    }
}

double get_time_ms(){
    static auto start = std::chrono::high_resolution_clock::now();
    auto now = std::chrono::high_resolution_clock::now();
    return std::chrono::duration<double, std::milli>(now - start).count();
}

void runbench_warmup(double *cd, size_t size){
    const size_t reduced_grid_size = size/(ELEMENTS_PER_THREAD)/128;
    const int BLOCK_SIZE = 256;

    benchmark_func<short, BLOCK_SIZE, ELEMENTS_PER_THREAD, FUSION_DEGREE, 0, true>(1, (short*)cd, size);
}

template<unsigned int compute_iterations>
void runbench(double *cd, size_t size){
    const size_t compute_grid_size = size/ELEMENTS_PER_THREAD/FUSION_DEGREE;
    const int BLOCK_SIZE = 256;
    const long long computations = (ELEMENTS_PER_THREAD*(long long)compute_grid_size+(2*ELEMENTS_PER_THREAD*compute_iterations)*(long long)compute_grid_size)*FUSION_DEGREE;
    const long long memoryoperations = size;

    double start_time = get_time_ms();
    benchmark_func<float, BLOCK_SIZE, ELEMENTS_PER_THREAD, FUSION_DEGREE, compute_iterations, false>(1.0f, (float*)cd, size);
    double kernel_time_mad_sp = get_time_ms() - start_time;

    start_time = get_time_ms();
    benchmark_func<double, BLOCK_SIZE, ELEMENTS_PER_THREAD, FUSION_DEGREE, compute_iterations, false>(1.0, cd, size);
    double kernel_time_mad_dp = get_time_ms() - start_time;

    start_time = get_time_ms();
    benchmark_func<int, BLOCK_SIZE, ELEMENTS_PER_THREAD, FUSION_DEGREE, compute_iterations, true>(1, (int*)cd, size);
    double kernel_time_mad_int = get_time_ms() - start_time;

    printf("         %4d,   %8.3f,%8.2f,%8.2f,%7.2f,   %8.3f,%8.2f,%8.2f,%7.2f,  %8.3f,%8.2f,%8.2f,%7.2f\n",
        compute_iterations,
        ((double)computations)/((double)memoryoperations*sizeof(float)),
        kernel_time_mad_sp,
        ((double)computations)/kernel_time_mad_sp*1000./(double)(1000*1000*1000),
        ((double)memoryoperations*sizeof(float))/kernel_time_mad_sp*1000./(1000.*1000.*1000.),
        ((double)computations)/((double)memoryoperations*sizeof(double)),
        kernel_time_mad_dp,
        ((double)computations)/kernel_time_mad_dp*1000./(double)(1000*1000*1000),
        ((double)memoryoperations*sizeof(double))/kernel_time_mad_dp*1000./(1000.*1000.*1000.),
        ((double)computations)/((double)memoryoperations*sizeof(int)),
        kernel_time_mad_int,
        ((double)computations)/kernel_time_mad_int*1000./(double)(1000*1000*1000),
        ((double)memoryoperations*sizeof(int))/kernel_time_mad_int*1000./(1000.*1000.*1000.) );
}

